// lib/services/secret_service.dart
import 'dart:io';

class SecretService {
  static final Map<String, String> _secrets = {};

  static Future<void> initialize() async {
    // Priority 1: Dart defines (compile-time, passed via --dart-define)
    _loadFromDartDefines();

    // Priority 2: Environment variables (runtime)
    _loadFromEnvironment();

    // Priority 3: .env file in project root (development convenience)
    await _loadFromEnvFile();
  }

  static void _loadFromDartDefines() {
    const keys = [
      'AWS_ACCESS_KEY_ID',
      'AWS_SECRET_ACCESS_KEY',
      'AWS_S3_BUCKET',
      'AWS_REGION',
      'GOOGLE_CLOUD_API_KEY',
    ];

    const defines = {
      'AWS_ACCESS_KEY_ID':
          String.fromEnvironment('AWS_ACCESS_KEY_ID'),
      'AWS_SECRET_ACCESS_KEY':
          String.fromEnvironment('AWS_SECRET_ACCESS_KEY'),
      'AWS_S3_BUCKET': String.fromEnvironment('AWS_S3_BUCKET'),
      'AWS_REGION':
          String.fromEnvironment('AWS_REGION', defaultValue: 'us-east-1'),
      'GOOGLE_CLOUD_API_KEY':
          String.fromEnvironment('GOOGLE_CLOUD_API_KEY'),
    };

    for (final key in keys) {
      final value = defines[key];
      if (value != null && value.isNotEmpty) {
        _secrets[key] = value;
      }
    }
  }

  static void _loadFromEnvironment() {
    final envKeys = [
      'AWS_ACCESS_KEY_ID',
      'AWS_SECRET_ACCESS_KEY',
      'AWS_S3_BUCKET',
      'AWS_REGION',
      'GOOGLE_CLOUD_API_KEY',
    ];

    for (final key in envKeys) {
      if (!_secrets.containsKey(key) || _secrets[key]!.isEmpty) {
        final value = Platform.environment[key];
        if (value != null && value.isNotEmpty) {
          _secrets[key] = value;
        }
      }
    }
  }

  static Future<void> _loadFromEnvFile() async {
    try {
      final envFile = File('.env');
      if (await envFile.exists()) {
        final lines = await envFile.readAsLines();
        for (final line in lines) {
          final trimmed = line.trim();
          if (trimmed.isEmpty || trimmed.startsWith('#')) continue;

          final eqIndex = trimmed.indexOf('=');
          if (eqIndex == -1) continue;

          final key = trimmed.substring(0, eqIndex).trim();
          var value = trimmed.substring(eqIndex + 1).trim();

          // Strip surrounding quotes
          if ((value.startsWith('"') && value.endsWith('"')) ||
              (value.startsWith("'") && value.endsWith("'"))) {
            value = value.substring(1, value.length - 1);
          }

          if (!_secrets.containsKey(key) || _secrets[key]!.isEmpty) {
            _secrets[key] = value;
          }
        }
      }
    } catch (_) {
      // .env file not found or unreadable — that's fine
    }
  }

  static String get(String key, {String? defaultValue}) {
    return _secrets[key] ?? defaultValue ?? '';
  }

  static String require(String key) {
    final value = _secrets[key];
    if (value == null || value.isEmpty) {
      throw Exception('Required secret "$key" is not configured.');
    }
    return value;
  }

  static void validate() {
    final required = [
      'AWS_ACCESS_KEY_ID',
      'AWS_SECRET_ACCESS_KEY',
      'AWS_S3_BUCKET',
      'GOOGLE_CLOUD_API_KEY',
    ];

    final missing = <String>[];
    for (final key in required) {
      if (!_secrets.containsKey(key) || _secrets[key]!.isEmpty) {
        missing.add(key);
      }
    }

    if (missing.isNotEmpty) {
      throw Exception(
        'Missing required secrets:\n${missing.map((k) => '  • $k').join('\n')}\n\n'
        'Provide them via environment variables, .env file, or --dart-define flags.',
      );
    }
  }

  // Convenience getters
  static String get awsAccessKeyId => require('AWS_ACCESS_KEY_ID');
  static String get awsSecretAccessKey => require('AWS_SECRET_ACCESS_KEY');
  static String get awsS3Bucket => require('AWS_S3_BUCKET');
  static String get awsRegion => get('AWS_REGION', defaultValue: 'us-east-1');
  static String get googleCloudApiKey => require('GOOGLE_CLOUD_API_KEY');
}


// lib/services/s3_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:path/path.dart' as path;
import 'secret_service.dart';

class S3Service {
  late final String _accessKey;
  late final String _secretKey;
  late final String _bucket;
  late final String _region;

  S3Service() {
    _accessKey = SecretService.awsAccessKeyId;
    _secretKey = SecretService.awsSecretAccessKey;
    _bucket = SecretService.awsS3Bucket;
    _region = SecretService.awsRegion;
  }

  String get _host => '$_bucket.s3.$_region.amazonaws.com';

  Future<String> uploadFile(File file) async {
    final bytes = await file.readAsBytes();
    final fileName =
        'uploads/${DateTime.now().millisecondsSinceEpoch}_${path.basename(file.path)}';
    final contentType = _getContentType(file.path);

    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);

    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'Host': _host,
      'x-amz-date': amzDate,
      'x-amz-content-sha256': payloadHash,
      'Content-Type': contentType,
      'Content-Length': bytes.length.toString(),
    };

    final authHeader = _buildAuthorizationHeader(
      method: 'PUT',
      uri: '/$fileName',
      headers: headers,
      payloadHash: payloadHash,
      dateStamp: dateStamp,
      amzDate: amzDate,
    );

    headers['Authorization'] = authHeader;

    final url = Uri.https(_host, '/$fileName');
    final response = await http.put(url, headers: headers, body: bytes);

    if (response.statusCode == 200 || response.statusCode == 201) {
      return url.toString();
    } else {
      throw Exception(
          'S3 upload failed (${response.statusCode}): ${response.body}');
    }
  }

  String _buildAuthorizationHeader({
    required String method,
    required String uri,
    required Map<String, String> headers,
    required String payloadHash,
    required String dateStamp,
    required String amzDate,
  }) {
    final sortedHeaders = Map.fromEntries(
      headers.entries.toList()
        ..sort((a, b) =>
            a.key.toLowerCase().compareTo(b.key.toLowerCase())),
    );

    final canonicalHeaders = sortedHeaders.entries
        .map((e) => '${e.key.toLowerCase()}:${e.value.trim()}')
        .join('\n');

    final signedHeaders = sortedHeaders.keys
        .map((k) => k.toLowerCase())
        .join(';');

    final canonicalRequest = [
      method,
      Uri.encodeFull(uri),
      '', // query string
      '$canonicalHeaders\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$_region/s3/aws4_request';

    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(dateStamp);
    final signature = Hmac(sha256, signingKey)
        .convert(utf8.encode(stringToSign))
        .toString();

    return 'AWS4-HMAC-SHA256 '
        'Credential=$_accessKey/$credentialScope, '
        'SignedHeaders=$signedHeaders, '
        'Signature=$signature';
  }

  List<int> _getSignatureKey(String dateStamp) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$_secretKey'))
        .convert(utf8.encode(dateStamp))
        .bytes;
    final kRegion =
        Hmac(sha256, kDate).convert(utf8.encode(_region)).bytes;
    final kService =
        Hmac(sha256, kRegion).convert(utf8.encode('s3')).bytes;
    final kSigning =
        Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  String _formatDate(DateTime dt) =>
      '${dt.year}${_pad(dt.month)}${_pad(dt.day)}';

  String _formatAmzDate(DateTime dt) =>
      '${_formatDate(dt)}T${_pad(dt.hour)}${_pad(dt.minute)}${_pad(dt.second)}Z';

  String _pad(int n) => n.toString().padLeft(2, '0');

  String _getContentType(String filePath) {
    final ext = path.extension(filePath).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}


// lib/services/vision_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import 'secret_service.dart';

class VisionService {
  late final String _apiKey;

  VisionService() {
    _apiKey = SecretService.googleCloudApiKey;
  }

  Future<String> analyzeImage(File imageFile) async {
    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final url = Uri.parse(
      'https://vision.googleapis.com/v1/images:annotate?key=$_apiKey',
    );

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'FACE_DETECTION', 'maxResults': 5},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES', 'maxResults': 5},
          ],
        }
      ],
    };

    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode != 200) {
      throw Exception(
          'Vision API error (${response.statusCode}): ${response.body}');
    }

    final data = jsonDecode(response.body);
    return _formatResults(data);
  }

  String _formatResults(Map<String, dynamic> data) {
    final buffer = StringBuffer();
    final responses = data['responses'] as List?;

    if (responses == null || responses.isEmpty) {
      return 'No analysis results returned.';
    }

    final result = responses[0] as Map<String, dynamic>;

    // Labels
    final labels = result['labelAnnotations'] as List?;
    if (labels != null && labels.isNotEmpty) {
      buffer.writeln('📋 Labels:');
      for (final label in labels) {
        final desc = label['description'];
        final score = (label['score'] as num) * 100;
        buffer.writeln('  • $desc (${score.toStringAsFixed(1)}%)');
      }
      buffer.writeln();
    }

    // Text
    final textAnnotations = result['textAnnotations'] as List?;
    if (textAnnotations != null && textAnnotations.isNotEmpty) {
      buffer.writeln('📝 Detected Text:');
      buffer.writeln('  "${textAnnotations[0]['description']}"');
      buffer.writeln();
    }

    // Faces
    final faces = result['faceAnnotations'] as List?;
    if (faces != null && faces.isNotEmpty) {
      buffer.writeln('😀 Faces Detected: ${faces.length}');
      for (var i = 0; i < faces.length; i++) {
        final face = faces[i];
        buffer.writeln('  Face ${i + 1}:');
        buffer.writeln(
            '    Joy: ${_likelihoodEmoji(face['joyLikelihood'])}');
        buffer.writeln(
            '    Sorrow: ${_likelihoodEmoji(face['sorrowLikelihood'])}');
        buffer.writeln(
            '    Surprise: ${_likelihoodEmoji(face['surpriseLikelihood'])}');
      }
      buffer.writeln();
    }

    // Safe Search
    final safeSearch = result['safeSearchAnnotation'] as Map?;
    if (safeSearch != null) {
      buffer.writeln('🛡️ Safe Search:');
      buffer.writeln('  Adult: ${safeSearch['adult']}');
      buffer.writeln('  Violence: ${safeSearch['violence']}');
      buffer.writeln('  Racy: ${safeSearch['racy']}');
      buffer.writeln();
    }

    // Dominant Colors
    final imageProps = result['imagePropertiesAnnotation'] as Map?;
    if (imageProps != null) {
      final colors =
          imageProps['dominantColors']?['colors'] as List?;
      if (colors != null && colors.isNotEmpty) {
        buffer.writeln('🎨 Dominant Colors:');
        for (final color in colors.take(5)) {
          final c = color['color'] as Map;
          final r = (c['red'] ?? 0).toInt();
          final g = (c['green'] ?? 0).toInt();
          final b = (c['blue'] ?? 0).toInt();
          final score = ((color['score'] as num) * 100);
          buffer.writeln(
              '  • RGB($r, $g, $b) — ${score.toStringAsFixed(1)}%');
        }
      }
    }

    return buffer.toString().trim();
  }

  String _likelihoodEmoji(String? likelihood) {
    switch (likelihood) {
      case 'VERY_LIKELY':
        return '✅ Very Likely';
      case 'LIKELY':
        return '👍 Likely';
      case 'POSSIBLE':
        return '🤔 Possible';
      case 'UNLIKELY':
        return '👎 Unlikely';
      case 'VERY_UNLIKELY':
        return '❌ Very Unlikely';
      default:
        return '❓ Unknown';
    }
  }
}


